package com.ichi2.anki

import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.browser.CardBrowserViewModel
import org.hamcrest.MatcherAssert.assertThat
import org.hamcrest.Matchers.equalTo
import org.junit.Test
import org.junit.runner.RunWith

/**
 * Tests for card browser row selection behavior
 * Specifically tests the fix for: Card remains selected even after unselecting it
 */
@RunWith(AndroidJUnit4::class)
class CardBrowserRowSelectionTest : RobolectricTest() {

    /**
     * Tests that toggleRowSelectionAtPosition correctly adds a row when not selected
     */
    @Test
    fun toggleRowSelectionAtPosition_addsRowWhenNotSelected() {
        val browser = getBrowserWithNotes(3)
        val viewModel = browser.viewModel

        // Initially no rows selected
        assertThat("No rows should be selected initially", viewModel.selectedRowCount(), equalTo(0))

        // Toggle position 0 (should add it)
        viewModel.toggleRowSelectionAtPosition(0)
        assertThat("One row should be selected after toggle", viewModel.selectedRowCount(), equalTo(1))
        assertThat("Position 0 should be selected", viewModel.selectedRows.contains(viewModel.getRowAtPosition(0)), equalTo(true))
    }

    /**
     * Tests that toggleRowSelectionAtPosition correctly removes a row when already selected
     */
    @Test
    fun toggleRowSelectionAtPosition_removesRowWhenSelected() {
        val browser = getBrowserWithNotes(3)
        val viewModel = browser.viewModel

        // Select position 0
        viewModel.toggleRowSelectionAtPosition(0)
        assertThat("One row should be selected", viewModel.selectedRowCount(), equalTo(1))

        // Toggle position 0 again (should remove it)
        viewModel.toggleRowSelectionAtPosition(0)
        assertThat("No rows should be selected after untoggle", viewModel.selectedRowCount(), equalTo(0))
        assertThat("Position 0 should not be selected", viewModel.selectedRows.contains(viewModel.getRowAtPosition(0)), equalTo(false))
    }

    /**
     * Tests the bug scenario: Select card 1, then select card 2 and unselect card 1
     * This should result in only card 2 being selected
     */
    @Test
    fun toggleRowSelection_correctlyHandlesMultipleToggles() {
        val browser = getBrowserWithNotes(3)
        val viewModel = browser.viewModel

        // Select position 0
        viewModel.toggleRowSelectionAtPosition(0)
        assertThat("One row should be selected", viewModel.selectedRowCount(), equalTo(1))
        assertThat("Position 0 should be selected", viewModel.selectedRows.contains(viewModel.getRowAtPosition(0)), equalTo(true))

        // Select position 1
        viewModel.toggleRowSelectionAtPosition(1)
        assertThat("Two rows should be selected", viewModel.selectedRowCount(), equalTo(2))
        assertThat("Position 0 should still be selected", viewModel.selectedRows.contains(viewModel.getRowAtPosition(0)), equalTo(true))
        assertThat("Position 1 should be selected", viewModel.selectedRows.contains(viewModel.getRowAtPosition(1)), equalTo(true))

        // Unselect position 0
        viewModel.toggleRowSelectionAtPosition(0)
        assertThat("Only one row should be selected", viewModel.selectedRowCount(), equalTo(1))
        assertThat("Position 0 should not be selected", viewModel.selectedRows.contains(viewModel.getRowAtPosition(0)), equalTo(false))
        assertThat("Position 1 should still be selected", viewModel.selectedRows.contains(viewModel.getRowAtPosition(1)), equalTo(true))
    }

    /**
     * Helper method to create a browser with a specific number of notes
     */
    private fun getBrowserWithNotes(count: Int): CardBrowser {
        for (i in 0 until count) {
            addNoteUsingBasicModel("Front $i", "Back $i")
        }
        return CardBrowser().also {
            startActivityNormallyOpenCollectionWithIntent(it, CardBrowser.createIntent(targetContext, null))
            advanceRobolectricLooperWithSleep()
        }
    }
}
